import { useEffect, useState } from 'react';
import axios from 'axios';
import TurfCard from '../components/TurfCard';
import StatsBar from '../components/StatsBar';
import HowItWorks from '../components/HowItWorks';
import OffersSection from '../components/OffersSection';
import SportFilter from '../components/SportFilter';
import { useNavigate } from 'react-router-dom';
import logo from '../assets/logo.png';

const API = 'http://localhost:5000/api';

export default function Home() {
  const [turfs, setTurfs] = useState([]);
  const [sport, setSport] = useState('All');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    axios.get(`${API}/turfs`)
      .then(res => setTurfs(res.data))
      .catch(err => console.error('Failed to fetch turfs:', err));
  }, []);

  const fetchNearby = () => {
    setLoading(true);
    navigator.geolocation.getCurrentPosition(async pos => {
      const { latitude, longitude } = pos.coords;
      try {
        const res = await axios.get(
          `${API}/turfs/nearby?lat=${latitude}&lng=${longitude}&radius=10000`
        );
        setTurfs(res.data);
      } catch (err) {
        console.error('Failed to fetch nearby turfs:', err);
      }
      setLoading(false);
    }, () => {
      alert('Location access denied');
      setLoading(false);
    });
  };

  const filtered = sport === 'All' ? turfs : turfs.filter(t => t.sport === sport);

  return (
    <div>
      {/* Hero */}
      <div style={{
        background: 'linear-gradient(135deg, #0a3d2e 0%, #1ebe74 100%)',
        padding: '5rem 2rem',
        textAlign: 'center',
        color: 'white',
      }}>
        <img
          src={logo}
          alt="TurfX"
          style={{ height: '120px', objectFit: 'contain', marginBottom: '1.5rem' }}
        />
        <h1 style={{ fontSize: '3rem', fontWeight: '800', marginBottom: '0.5rem', letterSpacing: '-1px' }}>
          Book • Play • Enjoy ⚡
        </h1>
        <p style={{ fontSize: '1rem', opacity: 0.85, marginBottom: '0.5rem', letterSpacing: '2px', fontWeight: '600' }}>
          ONE TURF. EVERY GAME.
        </p>
        <p style={{ fontSize: '1.1rem', opacity: 0.9, marginBottom: '2.5rem' }}>
          Find nearby turfs, check availability, and play your favourite sport today.
        </p>
        <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center', flexWrap: 'wrap' }}>
          <button onClick={() => navigate('/explore')} style={{
            background: 'white', color: '#0a3d2e',
            border: 'none', padding: '14px 32px',
            borderRadius: '12px', fontSize: '1rem',
            fontWeight: '700', cursor: 'pointer',
          }}>
            Explore Turfs
          </button>
          <button onClick={fetchNearby} style={{
            background: 'transparent', color: 'white',
            border: '2px solid white', padding: '14px 32px',
            borderRadius: '12px', fontSize: '1rem',
            fontWeight: '700', cursor: 'pointer',
          }}>
            {loading ? 'Locating...' : '📍 Near Me'}
          </button>
        </div>
      </div>

      {/* Stats */}
      <StatsBar />

      {/* Turfs */}
      <div style={{ padding: '3rem 2rem', maxWidth: '1200px', margin: '0 auto' }}>
        <h2 style={{ fontSize: '1.8rem', marginBottom: '0.5rem' }}>Featured Turfs</h2>
        <p style={{ color: '#666', marginBottom: '1rem' }}>Top rated venues near you</p>
        <SportFilter selected={sport} onSelect={setSport} />
        {filtered.length === 0 ? (
          <p style={{ color: '#999', marginTop: '2rem', textAlign: 'center' }}>
            No turfs found.
          </p>
        ) : (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: '1.5rem',
            marginTop: '1rem',
          }}>
            {filtered.map(turf => <TurfCard key={turf.id} turf={turf} />)}
          </div>
        )}
      </div>

      {/* How It Works */}
      <HowItWorks />

      {/* Offers */}
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        <OffersSection />
      </div>
    </div>
  );
}
